parameters.jsonBody:
{
  "model": "deepseek-r1:1.5b",
  "messages": [
    {
      "role": "system",
      "content": "You are an adaptive tutor for a data science learning app.

You are given:
- A LESSON_TEXT (or relevant snippet)
- The original QUESTION and its CORRECT_ANSWER
- The USER_ANSWER that was wrong
- Metadata such as lesson_slug, topic, and level

Your job is:
1. Analyze the mistake: what concept(s) is the user missing?
2. Write a short MINI_LESSON that focuses only on those missing concepts.
3. Generate 2–5 REMEDIATION_QUESTIONS to help the user fix their misunderstanding.
4. Propose 3 FOLLOWUP_OPTIONS the UI can show as buttons.

Return ONLY valid JSON with this exact schema:

{
  "mini_lesson": {
    "title": string,
    "explanation": string,
    "bullet_points": string[],
    "suggested_code_example": string
  },
  "remediation_questions": [
    {
      "question": string,
      "answer": string,
      "difficulty": number,
      "category": string,
      "question_type": "short_answer",
      "source": "remediation"
    }
  ],
  "followup_options": string[]
}

Do not include any Markdown fences, commentary, or extra fields. Just the JSON."
    },
    {
      "role": "user",
      "content": "Lesson metadata:
- slug: {{ $json.lesson_slug }}
- title: {{ $json.lesson_title }}
- topic: {{ $json.topic }}
- level: {{ $json.level }}

ORIGINAL_QUESTION:
{{ $json.question_text }}

CORRECT_ANSWER:
{{ $json.correct_answer }}

USER_ANSWER:
{{ $json.user_answer }}

LESSON_TEXT:
{{ $json.lesson_text }}"
    }
  ],
  "temperature": 0.2
}

parameters.functionCode:
// Parse DeepSeek bundle and emit:
// - one item per remediation question (for DB)
// - one item with mini_lesson + followup_options (for frontend)

// DeepSeek returns OpenAI-style response: JSON is inside choices[0].message.content.
const raw =
  $json.choices &&
  Array.isArray($json.choices) &&
  $json.choices[0] &&
  $json.choices[0].message &&
  typeof $json.choices[0].message.content === 'string'
    ? $json.choices[0].message.content.trim()
    : '';

if (!raw) {
  throw new Error('LLM response is empty or missing choices[0].message.content');
}

let bundle;
try {
  bundle = JSON.parse(raw);
} catch (err) {
  throw new Error(
    'Failed to parse LLM JSON: ' +
      err.message +
      '\nRaw content (first 500 chars):\n' +
      raw.slice(0, 500)
  );
}

const miniLesson = bundle.mini_lesson || {};
const remediationQuestions = Array.isArray(bundle.remediation_questions)
  ? bundle.remediation_questions
  : [];
const followupOptions = Array.isArray(bundle.followup_options)
  ? bundle.followup_options
  : [];

// Get normalized metadata from Set – Lesson Metadata
const meta = $node['Set – Lesson Metadata'].json;

// 1) Items for remediation questions (to store in Supabase)
const items = remediationQuestions.map((q, index) => ({
  json: {
    type: 'remediation_question',
    // lesson-level
    lesson_slug: meta.lesson_slug,
    topic: meta.topic,
    level: meta.level,
    // user/traceability
    user_id: meta.user_id,
    original_question_id: meta.question_id,
    attempt_id: meta.attempt_id || null,
    // question-level
    question: q.question,
    answer: q.answer,
    difficulty: typeof q.difficulty === 'number' ? q.difficulty : 1,
    category: q.category || 'unspecified',
    question_type: q.question_type || 'short_answer',
    source: q.source || 'remediation',
    index
  }
}));

// 2) One extra item with the mini lesson + followup options (for the frontend)
items.push({
  json: {
    type: 'mini_lesson_payload',
    lesson_slug: meta.lesson_slug,
    topic: meta.topic,
    level: meta.level,
    mini_lesson: miniLesson,
    followup_options: followupOptions
  }
});

return items;
